function extractConversation() {
  const messages = [];

  // heuristic: most chat UIs use role-based containers
  const nodes = document.querySelectorAll("article, .message, .chat-message");

  nodes.forEach((node) => {
    const text = node.innerText?.trim();
    if (!text) return;

    const role =
      node.innerText.toLowerCase().includes("you")
        ? "user"
        : "ai";

    messages.push({
      role,
      content: text,
      timestamp: new Date().toISOString()
    });
  });

  return messages;
}

chrome.runtime.onMessage.addListener((msg, sender, sendResponse) => {
  if (msg.type === "EXTRACT_CHAT") {
    sendResponse({ messages: extractConversation() });
  }
});

