function extractConversation() {
  const messages = [];

  // Generic selector: works across many chat UIs
  const nodes = document.querySelectorAll("article, div");

  let index = 0;

  nodes.forEach((node) => {
    const text = node.innerText?.trim();
    if (!text || text.length < 5) return;

    // Try explicit role first
    let role = "unknown";

    const explicitRole = node.getAttribute("data-message-author-role");
    if (explicitRole === "user" || explicitRole === "assistant") {
      role = explicitRole;
    }

    // Detect code presence (observable, not inferred)
    const hasCode = node.querySelector("pre, code") !== null;

    messages.push({
      index,
      role,               // user | assistant | unknown
      raw_text: text,
      has_code: hasCode,
      char_length: text.length
    });

    index++;
  });

  return messages;
}

chrome.runtime.onMessage.addListener((msg, sender, sendResponse) => {
  if (msg.type === "EXTRACT_CHAT") {
    sendResponse({
      messages: extractConversation(),
      page_url: window.location.href
    });
  }
});

