/* ------------------------------ */
/* MESSAGE EXTRACTION HELPERS     */
/* ------------------------------ */

function extractCodeBlocks(node) {
  const blocks = [];
  node.querySelectorAll("pre, code").forEach((el) => {
    const text = el.innerText.trim();
    if (text) blocks.push(text);
  });
  return blocks;
}

function extractTextBlocks(node) {
  const blocks = [];
  node.childNodes.forEach((child) => {
    if (child.nodeType === Node.TEXT_NODE) {
      const text = child.textContent.trim();
      if (text) blocks.push(text);
    }
  });
  return blocks;
}

/* ------------------------------ */
/* MAIN SCRAPER                   */
/* ------------------------------ */

function scrapeConversation() {
  const messages = [];

  // ChatGPT structure currently uses article
  const nodes = document.querySelectorAll("article");

  nodes.forEach((node, i) => {
    const rawText = node.innerText.trim();
    if (!rawText) return;

    const codeBlocks = extractCodeBlocks(node);
    const textBlocks = extractTextBlocks(node);

    messages.push({
      index: i,

      // raw metadata (no inference here)
      role:
        node.getAttribute("data-message-author-role") ||
        "unknown",

      raw_text: rawText,

      text_blocks: textBlocks,
      code_blocks: codeBlocks,

      has_code: codeBlocks.length > 0,
      char_length: rawText.length,

      // optional but useful for debugging / future
      html_snapshot: node.innerHTML.slice(0, 2000)
    });
  });

  return messages;
}

/* ------------------------------ */
/* SCROLL TO LOAD HISTORY         */
/* ------------------------------ */

async function scrollToTop() {
  console.log("[CONTENT] Scrolling to load history");

  let lastHeight = 0;

  while (true) {
    window.scrollTo(0, 0);
    await new Promise((r) => setTimeout(r, 800));

    const newHeight = document.body.scrollHeight;

    if (newHeight === lastHeight) break;
    lastHeight = newHeight;
  }

  console.log("[CONTENT] Finished scrolling");
}

/* ------------------------------ */
/* MESSAGE LISTENER               */
/* ------------------------------ */

chrome.runtime.onMessage.addListener((msg, sender, sendResponse) => {
  if (msg.type !== "SCRAPE_CHAT") return;

  (async () => {
    try {
      console.log("[CONTENT] Starting extraction");

      await scrollToTop();

      const data = {
        url: window.location.href,
        title: document.title,
        timestamp: new Date().toISOString(),
        messages: scrapeConversation()
      };

      console.log("[CONTENT] Sending:", data.messages.length);

      sendResponse(data);
    } catch (err) {
      console.error("[CONTENT] Error:", err);
      sendResponse(null);
    }
  })();

  return true;
});

