/* =======================================================
   HELPERS
======================================================= */

function extractCodeBlocks(node) {
  const blocks = [];

  node.querySelectorAll("pre, code").forEach((el) => {
    const text = el.innerText?.trim();
    if (text) blocks.push(text);
  });

  return blocks;
}

function extractTextBlocks(node) {
  const blocks = [];

  node.querySelectorAll("p, li, h1, h2, h3, span, div").forEach((el) => {
    const text = el.innerText?.trim();
    if (text && text.length > 0) {
      blocks.push(text);
    }
  });

  return [...new Set(blocks)]; // remove duplicates
}

/* =======================================================
   SCROLL TO LOAD FULL HISTORY
======================================================= */

async function scrollToTop() {
  console.log("[CONTENT] Scrolling to load history");

  let lastHeight = 0;
  let stableCount = 0;

  while (stableCount < 3) {
    window.scrollTo(0, 0);

    await new Promise((r) => setTimeout(r, 900));

    const newHeight = document.body.scrollHeight;

    if (newHeight === lastHeight) {
      stableCount++;
    } else {
      stableCount = 0;
      lastHeight = newHeight;
    }
  }

  console.log("[CONTENT] Finished scrolling");
}

/* =======================================================
   MAIN SCRAPER
======================================================= */

function scrapeConversation() {
  const messages = [];

  // Primary selector
  let nodes = document.querySelectorAll("article");

  // Fallback (self-healing strategy)
  if (!nodes.length) {
    console.warn("[CONTENT] article not found, using fallback selector");
    nodes = [...document.querySelectorAll("div")]
      .filter((el) => el.innerText?.length > 80);
  }

  nodes.forEach((node, i) => {
    const rawText = node.innerText?.trim();
    if (!rawText) return;

    const codeBlocks = extractCodeBlocks(node);
    const textBlocks = extractTextBlocks(node);

    messages.push({
      index: i,

      // raw data only (NO intelligence)
      role:
        node.getAttribute("data-message-author-role") ||
        "unknown",

      raw_text: rawText,

      text_blocks: textBlocks,
      code_blocks: codeBlocks,

      has_code: codeBlocks.length > 0,
      char_length: rawText.length,

      // useful when DOM changes later
      html_snapshot: node.innerHTML.slice(0, 2500)
    });
  });

  return messages;
}

/* =======================================================
   MESSAGE LISTENER
======================================================= */

chrome.runtime.onMessage.addListener((msg, sender, sendResponse) => {

  if (msg.type !== "SCRAPE_CHAT") return;

  (async () => {
    try {
      console.log("[CONTENT] Starting extraction");

      await scrollToTop();

      const data = {
        url: window.location.href,
        title: document.title,
        timestamp: new Date().toISOString(),
        user_agent: navigator.userAgent,
        messages: scrapeConversation()
      };

      console.log("[CONTENT] Sending:", data.messages.length);

      sendResponse(data);

    } catch (err) {
      console.error("[CONTENT] Error:", err);
      sendResponse(null);
    }
  })();

  return true; // keep message channel open
});
